{
  "query": "query ProductBySku($sku: String!) { product(sku: $sku) { request_id data { id sku name warehouse_products { warehouse_id on_hand } } } }",
  "variables": { "sku": "{{sh_sku}}" }
}

{
  "query": "mutation InventoryAdd($data: UpdateInventoryInput!) { inventory_add(data: $data) { request_id } }",
  "variables": {
    "data": {
      "sku": "{{sh_sku}}",
      "warehouse_id": "{{sh_warehouse_id}}",
      "quantity": 1,
      "reason": "Postman delta add test"
    }
  }
}

{
  "query": "mutation InventoryRemove($data: UpdateInventoryInput!) { inventory_remove(data: $data) { request_id } }",
  "variables": {
    "data": {
      "sku": "{{sh_sku}}",
      "warehouse_id": "{{sh_warehouse_id}}",
      "quantity": 1,
      "reason": "Postman delta remove test"
    }
  }
}

{
  "query": "mutation InventoryReplace($data: ReplaceInventoryInput!) { inventory_replace(data: $data) { request_id } }",
  "variables": {
    "data": {
      "sku": "{{sh_sku}}",
      "warehouse_id": "{{sh_warehouse_id}}",
      "quantity": 9,
      "reason": "Postman block test"
    }
  }
}
